265	        cqi_E = cqi_E_vec;
266	    else
267	        cqi_E = cqi_E_vec(1);
268	    end
269	    W_E         = pmiInfo_E.W(:,:,1);
270	    cap_E       = real(log2(det(eye(nRxAntennas) + ...
271	        (1/nVar_wb) * (H_wb*W_E*(H_wb*W_E)'))));
272	    sinrPerRE_E = pmiInfo_E.SINRPerREPMI;
273	
274	else
275	    % ── L≥4: greedy DFT beam selection (OOM-safe) ────────────────────────
276	    % nrPMIReport pre-allocates Precoders(nTx,nLayers,C(nGrid,L),q1,q2):
277	    % C(1024,4)×128×4 entries > 5 GB → OOM. Greedy: O(L×nGrid) per rank.
278	    bestCap_E = -Inf;
279	    ri_E = 1;
280	    W_E  = zeros(nTxAntennas, 1);
281	    for rank_E = 1:maxRankE
282	        W_try  = greedyEType2R19Precoder(H_wb, panelDimensions, L_E, rank_E);
283	        HW_try = H_wb * W_try;
284	        cap_try = real(log2(det(eye(nRxAntennas) + ...
285	            (1/nVar_wb) * (HW_try * HW_try'))));
286	        if cap_try > bestCap_E
287	            bestCap_E = cap_try;  ri_E = rank_E;  W_E = W_try;
288	        end
289	    end
290	    cap_E = bestCap_E;
291	
292	    % SINR per layer: ZF receiver on wideband H (same as Approach B)
293	    H_eff_E = H_wb * W_E;
294	    W_zf_E  = pinv(H_eff_E);
295	    sinr_E  = zeros(ri_E, 1);
296	    for lyr = 1:ri_E
297	        sig  = abs(W_zf_E(lyr,:) * H_eff_E(:,lyr))^2;
298	        intf = sum(abs(W_zf_E(lyr,:) * H_eff_E).^2) - sig;
299	        nse  = nVar_wb * norm(W_zf_E(lyr,:))^2;
300	        sinr_E(lyr) = sig / (intf + nse);
301	    end
302	
303	    % CQI: wideband SINR → table lookup (same cqi_tbl as Approach B)
304	    sinr_E_dB = 10*log10(max(sinr_E, 1e-10));
305	    cqi_E     = max(sum(mean(sinr_E_dB) >= cqi_tbl), 1);
306	
307	    % sinrPerRE_E: replicate wideband SINR [nRE × ri_E] for computeMetrics
308	    sinrPerRE_E = repmat(sinr_E.', carrier.NSizeGrid * 12, 1);
309	end
310	
311	fb.ri_E        = ri_E;
312	fb.cqi_E       = cqi_E;
313	fb.cap_E       = cap_E;
314	fb.W_E         = W_E;
315	fb.sinrPerRE_E = sinrPerRE_E;
316	
317	end
