323	function W = greedyEType2R19Precoder(H_wb, panelDimensions, L, nLayers)
324	%GREEDYETYPE2R19PRECODER  eTypeII-r19 precoder via greedy DFT beam selection.
325	%
326	%  Dual-pol DFT codebook structure per TS 38.214 §5.2.2.2.5:
327	%    W = W1 * W2
328	%  W1: L DFT beams per polarization selected by greedy matching pursuit.
329	%  W2: combining coefficients from projected SVD.
330	%
331	%  Inputs:
332	%    H_wb          - [nRx × 2*N1*N2] wideband channel matrix
333	%    panelDimensions - [Ng, N1, N2]
334	%    L             - number of beams
335	%    nLayers       - number of spatial layers (rank)
336	%
337	%  Output:
338	%    W - [2*N1*N2 × nLayers] unit-Frobenius-norm precoder (||W||_F = 1)
339	
340	    N1 = panelDimensions(2);
341	    N2 = panelDimensions(3);
342	    O1 = 4;  O2 = 4;          % fixed oversampling per §5.2.2.2.5a
343	    nPerPol = N1 * N2;
344	
345	    % ── Oversampled DFT grid A [nPerPol × O1*N1*O2*N2] ──────────────────
346	    % u_{n1,n2} = a_{N1,O1}(n1) ⊗ a_{N2,O2}(n2)  (TS 38.214 §5.2.2.2.3)
347	    k1 = (0:N1-1)';  k2 = (0:N2-1)';
348	    nGrid = N1*O1 * N2*O2;
349	    A = zeros(nPerPol, nGrid);
350	    col = 0;
351	    for n1 = 0:N1*O1-1
352	        a1 = exp(1j*2*pi*n1*k1/(N1*O1)) / sqrt(N1);
353	        for n2 = 0:N2*O2-1
354	            col = col + 1;
355	            a2 = exp(1j*2*pi*n2*k2/(N2*O2)) / sqrt(N2);
356	            A(:, col) = kron(a1, a2);
357	        end
358	    end
359	
360	    % ── Greedy matching pursuit — shared beams for both polarizations ─────
361	    H1 = H_wb(:, 1:nPerPol);        % pol-1  [nRx × nPerPol]
362	    H2 = H_wb(:, nPerPol+1:end);    % pol-2  [nRx × nPerPol]
363	    R1 = H1;  R2 = H2;
364	    B  = zeros(nPerPol, L);
365	    for l = 1:L
366	        scores     = sum(abs(R1*A).^2 + abs(R2*A).^2, 1);
367	        [~, best]  = max(scores);
368	        a_sel      = A(:, best);
369	        B(:, l)    = a_sel;
370	        R1 = R1 - (R1 * a_sel) * a_sel';   % orthogonal deflation
371	        R2 = R2 - (R2 * a_sel) * a_sel';
372	    end
373	
374	    % ── W1: dual-pol block-diagonal [2*nPerPol × 2L] ─────────────────────
375	    W1 = [B, zeros(nPerPol,L); zeros(nPerPol,L), B];
376	
377	    % ── W2: combining coefficients via projected SVD [2L × nLayers] ──────
378	    [~, ~, Vp] = svd(H_wb * W1, 'econ');
379	    W2 = Vp(:, 1:min(nLayers, size(Vp,2)));
